let Baseline = materialize(
    SecurityEvent
    | where TimeGenerated > ago(24h)
    | where Account !endswith "$" and isnotempty(Account)
);
let LogonEvents   = Baseline | where EventID in (4624, 4625, 4634);
let ProcessEvents = Baseline | where EventID == 4688;
union LogonEvents, ProcessEvents
| summarize count() by Account, EventID

